/** Evidence hint identifiers mapped by the backend SignalToEvidenceMapper. */

export const EVIDENCE_HINTS = {
  buildMetadata: 'build_metadata',
  sbom: 'sbom',
  githubArtifactAttestation: 'github_artifact_attestation',
  slsaProvenance: 'slsa_provenance',
  intotoAttestation: 'intoto_attestation',
  sigstoreSignature: 'sigstore_signature',
  vulnerabilityScan: 'vulnerability_scan',
  releaseContext: 'release_context',
  deploymentMetadata: 'deployment_metadata',
  authHealth: 'auth_health',
} as const;

export type EvidenceHint = (typeof EVIDENCE_HINTS)[keyof typeof EVIDENCE_HINTS];

export function evidenceHints(...hints: EvidenceHint[]): string[] {
  return [...new Set(hints.filter(Boolean))];
}
